import{_ as e,o,c as s,an as i}from"./chunks/framework.DKgvuBLA.js";const m=JSON.parse('{"title":"Política de Privacidade","description":"","frontmatter":{},"headers":[],"relativePath":"pt/privacy-policy.md","filePath":"pt/privacy-policy.md"}'),t={name:"pt/privacy-policy.md"};function r(d,a,n,l,c,p){return o(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="politica-de-privacidade" tabindex="-1">Política de Privacidade <a class="header-anchor" href="#politica-de-privacidade" aria-label="Permalink to &quot;Política de Privacidade&quot;">​</a></h1><p>Esta página explica como <code>particles.js.org</code> lida com dados pessoais relacionados a análises e serviços de publicidade.</p><h2 id="escopo" tabindex="-1">Escopo <a class="header-anchor" href="#escopo" aria-label="Permalink to &quot;Escopo&quot;">​</a></h2><p>Esta política abrange o site de documentos e páginas relacionadas veiculadas por <code>particles.js.org</code>.</p><h2 id="dados-que-processamos" tabindex="-1">Dados que processamos <a class="header-anchor" href="#dados-que-processamos" aria-label="Permalink to &quot;Dados que processamos&quot;">​</a></h2><ul><li>Dados técnicos de navegação (metadados derivados de IP, agente de usuário, referenciador, URLs de páginas).</li><li>Eventos analíticos para tendências de uso de documentação.</li><li>Eventos relacionados com publicidade exigidos pelo Google AdSense quando o consentimento é concedido.</li></ul><h2 id="servicos-usados" tabindex="-1">Serviços usados <a class="header-anchor" href="#servicos-usados" aria-label="Permalink to &quot;Serviços usados&quot;">​</a></h2><ul><li><strong>Google Analytics 4</strong> para análise de tráfego e uso.</li><li><strong>Google AdSense</strong> para entrega de anúncios e medição de campanhas.</li></ul><h2 id="base-legal-e-consentimento" tabindex="-1">Base legal e consentimento <a class="header-anchor" href="#base-legal-e-consentimento" aria-label="Permalink to &quot;Base legal e consentimento&quot;">​</a></h2><ul><li>O armazenamento técnico essencial é utilizado para a operação do local.</li><li>As tecnologias de análise e publicidade só são ativadas após consentimento explícito através do banner de cookies.</li><li>Você pode rejeitar o consentimento e continuar usando os documentos.</li></ul><h2 id="armazenamento-de-consentimento" tabindex="-1">Armazenamento de consentimento <a class="header-anchor" href="#armazenamento-de-consentimento" aria-label="Permalink to &quot;Armazenamento de consentimento&quot;">​</a></h2><ul><li>A escolha de consentimento é armazenada localmente no armazenamento do navegador sob uma chave específica do site.</li><li>Nenhuma análise/rastreamento de anúncios é ativado antes que o consentimento seja aceito.</li></ul><h2 id="compartilhamento-de-dados" tabindex="-1">Compartilhamento de dados <a class="header-anchor" href="#compartilhamento-de-dados" aria-label="Permalink to &quot;Compartilhamento de dados&quot;">​</a></h2><ul><li>Os dados podem ser processados pelo Google como um processador/controlador terceirizado de acordo com os termos de serviço do Google.</li><li>Não vendemos dados pessoais através deste site.</li></ul><h2 id="seus-controles" tabindex="-1">Seus controles <a class="header-anchor" href="#seus-controles" aria-label="Permalink to &quot;Seus controles&quot;">​</a></h2><ul><li>Aceitar ou rejeitar através do banner de cookies.</li><li>Limpe os dados do site do navegador (armazenamento local/cookies) para redefinir sua escolha.</li><li>Use os controles de privacidade do navegador e as configurações de anúncios para restrições adicionais.</li></ul><h2 id="atualizacoes-de-politicas" tabindex="-1">Atualizações de políticas <a class="header-anchor" href="#atualizacoes-de-politicas" aria-label="Permalink to &quot;Atualizações de políticas&quot;">​</a></h2><p>Esta política pode ser atualizada quando os recursos de rastreamento ou os requisitos legais mudam.</p><h2 id="contato" tabindex="-1">Contato <a class="header-anchor" href="#contato" aria-label="Permalink to &quot;Contato&quot;">​</a></h2><p>Para solicitações de privacidade, utilize os canais de suporte e contato no repositório do projeto: <a href="https://github.com/tsparticles/tsparticles" target="_blank" rel="noreferrer">https://github.com/tsparticles/tsparticles</a></p>',20)])])}const h=e(t,[["render",r]]);export{m as __pageData,h as default};
